const fs = require('fs');
const path = require('path');

const ROOT_DIR = path.resolve(__dirname, '..');
const CODE_DIR = path.join(ROOT_DIR, 'code');

// Ensure 'code' directory exists
if (!fs.existsSync(CODE_DIR)) {
  fs.mkdirSync(CODE_DIR, { recursive: true });
}

// Date in format ggmmyyyy
const now = new Date();
const dd = String(now.getDate()).padStart(2, '0');
const mm = String(now.getMonth() + 1).padStart(2, '0');
const yyyy = now.getFullYear();
const dateStr = `${dd}${mm}${yyyy}`;

// Define the categories with match functions
const CATEGORIES = {
  all: {
    name: `grovkornet_all_${dateStr}.txt`,
    match: (relativePath, ext) => {
      const allowedExts = new Set(['.ts', '.tsx', '.js', '.jsx', '.kt', '.java', '.cpp', '.h', '.hpp', '.css']);
      return allowedExts.has(ext);
    }
  },
  typescript: {
    name: `grovkornet_typescript_${dateStr}.txt`,
    match: (relativePath, ext) => {
      // Merge typescript, javascript and css as requested
      const allowedExts = new Set(['.ts', '.tsx', '.js', '.jsx', '.css']);
      return allowedExts.has(ext);
    }
  },
  cpp: {
    name: `grovkornet_cpp_${dateStr}.txt`,
    match: (relativePath, ext) => {
      const allowedExts = new Set(['.cpp', '.h', '.hpp']);
      return allowedExts.has(ext);
    }
  },
  kotlin: {
    name: `grovkornet_kotlin_${dateStr}.txt`,
    match: (relativePath, ext) => {
      const allowedExts = new Set(['.kt', '.java']);
      return allowedExts.has(ext);
    }
  },
  codegen_graphrag: {
    name: `grovkornet_codegen_graphrag_${dateStr}.txt`,
    match: (relativePath, ext) => {
      const normalizedPath = relativePath.replace(/\\/g, '/');
      const isInCodegen = normalizedPath.includes('packages/shared/scripts/codegen/');
      const isInGraphrag = normalizedPath.includes('packages/shared/scripts/graphrag/');
      if (normalizedPath.endsWith('output.graph.json')) {
        return false;
      }
      const allowedExts = new Set(['.js', '.jsx', '.ts', '.tsx', '.json', '.yaml', '.yml']);
      return (isInCodegen || isInGraphrag) && allowedExts.has(ext);
    }
  }
};

const EXCLUDED_DIRS = new Set([
  'node_modules',
  '.git',
  '.expo',
  '.turbo',
  'coverage',
  '.cache',
  '.cxx',
  'filament-host',
  'filament',
  '.next',
  'out',
  'dist',
  'web-build',
  '.eas',
  '.metro',
  '.metro-cache',
  '.stryker-tmp',
  'reports',
  'code' // Exclude output directory
]);

// Specific exclusions of relative paths (e.g. autogenerated paths)
const EXCLUDED_RELATIVE_PATHS = [
  path.join('apps', 'mobile', 'android'),
  path.join('apps', 'mobile', 'ios')
];

function shouldExclude(dirPath) {
  const relativePath = path.relative(ROOT_DIR, dirPath);
  
  // Check if it contains an excluded folder in the path segments
  const segments = relativePath.split(path.sep);
  if (segments.some(seg => EXCLUDED_DIRS.has(seg))) {
    return true;
  }
  
  // Check specific relative paths
  if (EXCLUDED_RELATIVE_PATHS.some(p => relativePath.startsWith(p) || relativePath === p)) {
    return true;
  }
  
  return false;
}

function walk(dir, fileList = []) {
  if (shouldExclude(dir)) {
    return fileList;
  }

  const files = fs.readdirSync(dir);
  for (const file of files) {
    const filePath = path.join(dir, file);
    const stat = fs.statSync(filePath);

    if (stat.isDirectory()) {
      walk(filePath, fileList);
    } else {
      const ext = path.extname(file).toLowerCase();
      const relativePath = path.relative(ROOT_DIR, filePath);
      
      let matchesAny = false;
      for (const category of Object.values(CATEGORIES)) {
        if (category.match(relativePath, ext)) {
          matchesAny = true;
          break;
        }
      }
      
      if (matchesAny) {
        fileList.push(filePath);
      }
    }
  }
  return fileList;
}

function main() {
  console.log('Starting custom source code scanning...');
  const files = walk(ROOT_DIR);
  console.log(`Found ${files.length} matching files.`);

  // Clean up legacy single file if present
  const oldOutputFile = path.join(ROOT_DIR, 'grovkornet_source_bundle.txt');
  if (fs.existsSync(oldOutputFile)) {
    try {
      fs.unlinkSync(oldOutputFile);
      console.log(`Cleaned up legacy file: ${oldOutputFile}`);
    } catch (err) {
      console.error(`Error deleting legacy file:`, err.message);
    }
  }

  // Initialize buffers for each category
  const buffers = {};
  const processedCounts = {};
  for (const key of Object.keys(CATEGORIES)) {
    buffers[key] = '';
    processedCounts[key] = 0;
  }

  for (const file of files) {
    const relativePath = path.relative(ROOT_DIR, file);
    const ext = path.extname(file).toLowerCase();
    try {
      const content = fs.readFileSync(file, 'utf8');
      
      const fileHeader = '='.repeat(80) + '\n' +
                         `File: ${relativePath}\n` +
                         '='.repeat(80) + '\n\n';
      const fileFooter = '\n\n';
      const fileEntry = fileHeader + content + fileFooter;

      for (const [key, category] of Object.entries(CATEGORIES)) {
        if (category.match(relativePath, ext)) {
          buffers[key] += fileEntry;
          processedCounts[key]++;
        }
      }
    } catch (err) {
      console.error(`Error reading ${relativePath}:`, err.message);
    }
  }

  console.log('\n--- BUNDLE COMPLETE ---');
  for (const [key, category] of Object.entries(CATEGORIES)) {
    const outputPath = path.join(CODE_DIR, category.name);
    fs.writeFileSync(outputPath, buffers[key], 'utf8');
    const stats = fs.statSync(outputPath);
    const sizeInMb = (stats.size / (1024 * 1024)).toFixed(2);
    
    console.log(`[${key.toUpperCase()}]`);
    console.log(`  File: ${category.name}`);
    console.log(`  Path: ${outputPath}`);
    console.log(`  Count: ${processedCounts[key]} files`);
    console.log(`  Size: ${sizeInMb} MB`);
  }
}

main();
